// Project and Workspace Mapping
const projectInput = ($('When Form Submitted').item.json["Project to upload"] || "")
  .toString()
  .trim();

const projectMap = {
  projectCode1: "qaseProjectCode1",
  projectCode2: "qaseProjectCode2",
  projectCode3: "qaseProjectCode3",
  projectCode4: "qaseProjectCode3",
};

// Severity Mapping
const severityMap = {
  "not set": 0,
  blocker: 1,
  critical: 2,
  major: 3,
  normal: 4,
  minor: 5,
  trivial: 6,
};

// Priority Mapping
const priorityMap = { "not set": 0, high: 1, medium: 2, low: 3 };

// Test Type Mapping (Based on QASE API IDs)
const typeMap = {
  other: 1,
  smoke: 2,
  regression: 3,
  security: 4,
  usability: 5,
  performance: 6,
  acceptance: 7,
  functional: 8,
  compatibility: 9,
  integration: 10,
  exploratory: 11,
};

// Layer Mapping
const layerMap = {
  "not set": 0,
  e2e: 1,
  api: 2,
  unit: 3,
};

// Automation Status Mapping
const automationMap = {
  "not-to-be-automated": 0,
  "to-be-automated": 1,
  automated: 2,
};

// Behavior Mapping
const behaviorMap = {
  "not set": 1,
  positive: 2,
  negative: 3,
};

// Helper function to resolve ID from input string
const getID = (map, value, defaultValue) => {
  if (value === undefined || value === null) return defaultValue;
  const cleanValue = value.toString().trim().toLowerCase().replace(/\s+/g, "-");
  const key = Object.keys(map).find(
    (k) => k.replace(/\s+/g, "-") === cleanValue,
  );
  return key !== undefined ? map[key] : defaultValue;
};

// Test Steps Parsing (Input format: "Action;Expected|Action;Expected")
let formattedSteps = [];
if ($json.steps_raw && $json.steps_raw.includes(";")) {
  formattedSteps = $json.steps_raw.split("|").map((step, index) => {
    const [action, expected] = step.split(";");
    return {
      position: index + 1,
      action: action ? action.trim() : "",
      expected_result: expected ? expected.trim() : "",
    };
  });
}

// Payload Construction
return {
  project_code: projectMap[projectInput] || "UNKNOWN",
  title: $json.title || "Untitled Test Case",
  description: $json.description || "",
  preconditions: $json.preconditions || "",
  postconditions: $json.postconditions || "",

  // Field ID resolution
  severity: getID(severityMap, $json.severity, 4),
  priority: getID(priorityMap, $json.priority, 2),
  type: getID(typeMap, $json.type, 8),
  layer: getID(layerMap, $json.layer, 0),
  behavior: getID(behaviorMap, $json.behavior, 1),
  automation: getID(automationMap, $json.automation, 0),

  status: 0, // 0 = Actual
  steps: formattedSteps,
};
